function weekCountdown(){const now=new Date(),next=new Date(now),day=(now.getDay()+6)%7;next.setHours(0,0,0,0);next.setDate(now.getDate()-day+7);let sec=Math.max(0,Math.floor((next-now)/1000)),d=Math.floor(sec/86400);sec%=86400;const h=Math.floor(sec/3600),m=Math.floor(sec%3600/60);return `${d}天 ${String(h).padStart(2,'0')}:${String(m).padStart(2,'0')}`;}
function resetCountdown(){const now=new Date(),next=new Date(now);next.setHours(24,0,0,0);let sec=Math.max(0,Math.floor((next-now)/1000));const h=Math.floor(sec/3600);sec%=3600;const m=Math.floor(sec/60),s=sec%60;return [h,m,s].map(v=>String(v).padStart(2,'0')).join(':');}
function updateResetClocks(){document.querySelectorAll('.four-reset-clock').forEach(e=>e.textContent=resetCountdown());document.querySelectorAll('.four-week-clock').forEach(e=>e.textContent=weekCountdown());}
