 const er=s.explore.run,exploreHtml=`<h3>🧭 地城探索</h3><div class="four-reset">每日可探索 2 次｜今日 ${s.explore.used}/2</div>${er?`<div class="four-card"><b>第 ${er.room}/5 房｜探索體力 ${er.energy}/100</b><small>${er.log.slice(0,4).join('<br>')}</small></div><div class="four-explore-actions"><button onclick="fourExploreChoose('fight')">⚔ 戰鬥房<br><small>穩定金幣與符文粉塵</small></button><button onclick="fourExploreChoose('treasure')">🎁 寶箱房<br><small>高報酬但可能是陷阱</small></button><button onclick="fourExploreChoose('rest')">💧 恢復泉<br><small>恢復探索體力</small></button></div>`:`<div class="four-card"><b>隨機五房探索</b><small>每個房間選擇戰鬥、寶箱或休息路線。完成五房可取得符文粉塵、寵物口糧、探索徽記與金幣。</small></div><button ${s.explore.used>=2?'disabled':''} onclick="fourExploreStart()">開始探索</button>`}`;
